function main({tableData}) {
    // 按行分割表格数据
    const lines = tableData.trim().split('\n');

    // 找到数据行（跳过表头和分隔符行）
    let dataLine = '';
    for (let i = 2; i < lines.length; i++) {
        if (lines[i].trim() && !lines[i].includes('---')) {
            dataLine = lines[i];
            break;
        }
    }

    // 解析数据行，按 | 分割并去除空白
    const fields = dataLine.split('|').map(field => field.trim()).filter(field => field);

    // 提取简历链接中的URL
    let resumeLink = fields[1] || '';
    const linkMatch = resumeLink.match(/\[.*?\]\((.*?)\)/);
    if (linkMatch) {
        resumeLink = linkMatch[1];
    }

    return {
        name: fields[0] || '',
        resumeLink: resumeLink,
        phone: fields[2] || '',
        wechat: fields[3] || '',
        email: fields[4] || '',
        skills: fields[5] || '',
        education: fields[6] || '',
        graduationTime: fields[7] || '',
        certificates: fields[8] || ''
    };
}

function main({inputText}) {
    // 找到第一个换行符的位置
    const firstNewlineIndex = inputText.indexOf('\n');

    // 如果没有换行符，整个文本就是第一行
    if (firstNewlineIndex === -1) {
        return {
            firstLine: inputText,
            remainingContent: ''
        };
    }

    // 提取第一行（不包含换行符）
    const firstLine = inputText.substring(0, firstNewlineIndex);

    // 提取剩余内容并移除所有换行符（包括 \n, \r, \r\n）
    const remainingContent = inputText
        .substring(firstNewlineIndex + 1)
        .replace(/[\r\n]+/g, '');

    return {
        firstLine,
        remainingContent
    };
}

