function main({num1, num2, num3, num4}) {

    function extractNumber(str) {
        if (!str) return 0;

        // 移除常见的Markdown标记：**、*、###、##、#、_、~~等
        const cleaned = str.replace(/[\*#_~`]/g, '').trim();

        // 提取数字（支持整数、小数、负数）
        const match = cleaned.match(/-?\d+\.?\d*/);

        return match ? parseFloat(match[0]) : 0;
    }

    const sum = (
        extractNumber(num1) + 
        extractNumber(num2) + 
        extractNumber(num3) + 
        extractNumber(num4)
    ).toString();

    return { sum };
}

